const input = $input.first().json;
const query = input.query || input.body || {};
const { id } = query;

if (!id) {
  throw new Error('Falta el parámetro requerido: id');
}

const sqlQuery = `SELECT id, nombre, apellido, whatsapp, email, telefono, lead_tipo, origen, categoria, nivel, objetivo, resumen, disponibilidad, tags, estado, estado_motivo, estado_fecha, primer_contacto, ultimo_contacto, proxima_cita, alumno_id, fecha_conversion, notas, created_at, updated_at FROM leads WHERE id = ${parseInt(id)};`;

return [{json: {sqlQuery}}];

const result = $('get_lead').first().json;

if (!result) {
  return [{json: {success: false, message: 'Lead no encontrado'}}];
}

return [{json: {success: true, lead: result}}];
